-- =============================================================================
-- Abhinaya Cinemas — Historical DCR backfill — SCRIPT 1: CATALOG
-- Run on the console's Supabase DB (the one the app uses). STAGING first.
-- Idempotent. After this, run the entry chunks 02_entries_partN.sql in order.
--
-- Populates BOTH the config JSONB (what the app reads) AND the normalized
-- catalog tables (movies/classes/screens/price_cards) that the live DB's
-- consistency trigger enforces. cinema_id is taken from the existing screens.
-- =============================================================================
-- 0) Safety: confirm we're on the console DB
do $$
begin
  if to_regclass('public.config') is null or to_regclass('public.entries') is null then
    raise exception 'config/entries tables not found — run this on the Abhinaya DCR database.';
  end if;
end $$;

