{"id": "mhf92d99d9", "name": "ULLOZHUKKU", "distributor": "CENTRAL PICTURES", "release": "2024-06-21", "share": 60}, {"id": "mhf93262d8", "name": "ORU JAATHI ORU JAATHAKAM", "distributor": "VARNACHITHRAFILMS", "release": "2025-01-31", "share": 60}, {"id": "mhf93a38d2", "name": "NALPATHIYONNU", "distributor": "LJ FILMS", "release": "2019-11-08", "share": 50}, {"id": "mhf9ace68e", "name": "VYSANA SAMETHAM BANDHUMITHRATHIKAL", "distributor": "ICON CINEMAS", "release": "2025-06-13", "share": 60}, {"id": "mhf9d42fb4", "name": "THUNIVU", "distributor": "SREE GOKULAM MOVIES", "release": "2023-01-11", "share": 55}, {"id": "mhfa827d13", "name": "DEAR FRIEND", "distributor": "CENTRAL PICTURES", "release": "2022-06-10", "share": 60}, {"id": "mhfaa37ff1", "name": "SUPER ZINDAGI", "distributor": "DREAM BIG FILMS", "release": "2024-08-09", "share": 50}, {"id": "mhfafa37b5", "name": "THANKAMANI", "distributor": "DREAM BIG FILMS", "release": "2024-03-07", "share": 60}, {"id": "mhfb9d22de", "name": "BHEESHMA PARVAM", "distributor": "A&A RELEASE", "release": "2022-03-03", "share": 60}, {"id": "mhfc6e9cfa", "name": "SUPER SHARANYA", "distributor": "CENTRAL PICTURES", "release": "2022-01-07", "share": 60}, {"id": "mhfdb04584", "name": "Written & Directed by God", "distributor": "GOODWILL FILMS", "release": "2025-06-05", "share": 60}, {"id": "mhfdd3a8eb", "name": "MONSTER", "distributor": "AASHIRVAD RELEASE", "release": "2022-10-21", "share": 60}, {"id": "mhfeb15cfc", "name": "SOOTHRAVAKYAM", "distributor": "CENTURY", "release": "2025-07-11", "share": 60}]'::jsonb; screens jsonb := '[]'::jsonb; scr jsonb;
begin
  select data into d from public.config where id = 1;
  if d is null then d := '{}'::jsonb; end if;
  d := jsonb_set(d, '{classes}', (
    select coalesce(jsonb_agg(c),'[]'::jsonb) from (
      select c from jsonb_array_elements(coalesce(d->'classes','[]'::jsonb)) c
      union all select c from jsonb_array_elements(new_classes) c
      where (c->>'id') not in (select x->>'id' from jsonb_array_elements(coalesce(d->'classes','[]'::jsonb)) x)
    ) t));
  for scr in select * from jsonb_array_elements(coalesce(d->'screens','[]'::jsonb)) loop
    if scr->>'id' = '7gwkvh9' then
      scr := jsonb_set(scr,'{classes}', a1_classes);
      scr := jsonb_set(scr,'{priceCards}', (select coalesce(jsonb_agg(c),'[]'::jsonb) from (
        select c from jsonb_array_elements(coalesce(scr->'priceCards','[]'::jsonb)) c
        union all select c from jsonb_array_elements(a1_cards) c
        where (c->>'id') not in (select x->>'id' from jsonb_array_elements(coalesce(scr->'priceCards','[]'::jsonb)) x)) t));
    elsif scr->>'id' = 'oxnv3cw' then
      scr := jsonb_set(scr,'{classes}', a2_classes);
      scr := jsonb_set(scr,'{priceCards}', (select coalesce(jsonb_agg(c),'[]'::jsonb) from (
        select c from jsonb_array_elements(coalesce(scr->'priceCards','[]'::jsonb)) c
        union all select c from jsonb_array_elements(a2_cards) c
        where (c->>'id') not in (select x->>'id' from jsonb_array_elements(coalesce(scr->'priceCards','[]'::jsonb)) x)) t));
    end if;
    screens := screens || jsonb_build_array(scr);
  end loop;
  d := jsonb_set(d,'{screens}', screens);
  d := jsonb_set(d,'{movies}', (select coalesce(jsonb_agg(m),'[]'::jsonb) from (
    select m from jsonb_array_elements(coalesce(d->'movies','[]'::jsonb)) m
    union all select m from jsonb_array_elements(new_movies) m
    where (m->>'id') not in (select x->>'id' from jsonb_array_elements(coalesce(d->'movies','[]'::jsonb)) x)) t));
  update public.config set data=d, updated_by='dcr-historical-import', updated_at=now() where id=1;
end $$;

-- 2) NORMALIZED catalog tables (movies/classes/screen_classes/price_cards)
do $$
declare cid uuid;
begin
  if to_regclass('public.movies') is null then
    return;  -- normalized layer not present; config-only DB, nothing to do here
  end if;
  select cinema_id into cid from public.screens where id = '7gwkvh9';
  if cid is null then raise exception 'screen 7gwkvh9 not found in public.screens'; end if;

  on conflict (id) do update set name=excluded.name, gst_pct=excluded.gst_pct;

  on conflict (screen_id, class_id) do update set seats=excluded.seats;

  on conflict (id) do nothing;

  on conflict (price_card_id, class_id) do update set price=excluded.price;

  on conflict (id) do nothing;
end $$;
-- Catalog done. Next: run 02_entries_part1ofN.sql ... in order.

-- 3) Active-layout flags (normalized layer) — historical-era assignments are
-- kept only so old entries compute; the app's active layout stays:
--   Audi 1: cls_royale / cls_lounge / cls_prime
--   Audi 2: 1u1lpa4 (Platinum) / lp9hi7s (Gold) / bsl9hd8 (Silver)
do $$
begin
  if to_regclass('public.screen_classes') is null then
    return;
  end if;
  alter table public.screen_classes
    add column if not exists active boolean not null default true;
  update public.screen_classes sc
  set active = case
    when sc.screen_id = '7gwkvh9'
      then sc.class_id in ('cls_royale', 'cls_lounge', 'cls_prime')
    when sc.screen_id = 'oxnv3cw'
      then sc.class_id in ('1u1lpa4', 'lp9hi7s', 'bsl9hd8')
    else true
  end
  where sc.screen_id in ('7gwkvh9', 'oxnv3cw');
end $$;
